+    local procedure ConvertNonDeductibleVATToJobCurrency(GenJnlLine: Record "Gen. Journal Line"; JobJnlLine: Record "Job Journal Line"): Decimal
+    begin
+        // If the journal line currency is the same as the job currency, no conversion is needed
+        if GenJnlLine."Currency Code" = JobJnlLine."Currency Code" then
+            exit(GenJnlLine."Non-Deductible VAT Amount");
+
+        // If job currency is empty (LCY), we need to convert from source currency to LCY
+        if JobJnlLine."Currency Code" = '' then
+            exit(CurrencyExchRate.ExchangeAmtFCYToLCY(
+                GenJnlLine."Posting Date",
+                GenJnlLine."Currency Code",
+                GenJnlLine."Non-Deductible VAT Amount",
+                GenJnlLine."Currency Factor"));
+
+        // If source currency is empty (LCY), we need to convert from LCY to job currency
+        if GenJnlLine."Currency Code" = '' then
+            exit(CurrencyExchRate.ExchangeAmtLCYToFCY(
+                GenJnlLine."Posting Date",
+                JobJnlLine."Currency Code",
+                GenJnlLine."Non-Deductible VAT Amount LCY",
+                JobJnlLine."Currency Factor"));
+
+        // Both source and job have different currencies: convert source to LCY, then LCY to job currency
+        exit(CurrencyExchRate.ExchangeAmtLCYToFCY(
+            GenJnlLine."Posting Date",
+            JobJnlLine."Currency Code",
+            CurrencyExchRate.ExchangeAmtFCYToLCY(
+                GenJnlLine."Posting Date",
+                GenJnlLine."Currency Code",
+                GenJnlLine."Non-Deductible VAT Amount",
+                GenJnlLine."Currency Factor"),
+            JobJnlLine."Currency Factor"));
+    end;
